"use strict";(self.webpackChunkdsd_project=self.webpackChunkdsd_project||[]).push([[5894],{6042:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"10-loi-sai-visualization","metadata":{"permalink":"/blog/10-loi-sai-visualization","source":"@site/blog/2024/03/14/2024-03-14-pitfall-visualize.md","title":"10 l\xf4\u0303i sai trong data visualization va\u0300 ca\u0301ch pho\u0300ng tra\u0301nh","description":"This is my first post on Docusaurus.","date":"2024-03-14T00:00:00.000Z","formattedDate":"14 th\xe1ng 3, 2024","tags":[{"label":"data visualization","permalink":"/blog/tags/data-visualization"},{"label":"histogram","permalink":"/blog/tags/histogram"},{"label":"seaborn","permalink":"/blog/tags/seaborn"},{"label":"plot","permalink":"/blog/tags/plot"}],"readingTime":2.56,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"10 l\xf4\u0303i sai trong data visualization va\u0300 ca\u0301ch pho\u0300ng tra\u0301nh","description":"This is my first post on Docusaurus.","slug":"10-loi-sai-visualization","authors":"lhduc","tags":["data visualization","histogram","seaborn","plot"],"image":"https://i.imgur.com/mErPwqL.png","hide_table_of_contents":false},"unlisted":false,"nextItem":{"title":"Ca\u0301ch bi\xea\u0309u di\xea\u0303n s\xf4\u0301 l\u01b0\u01a1\u0323ng va\u0300 khoa\u0309ng d\u01b0\u0303 li\xea\u0323u cho Histogram du\u0300ng Seaborn va\u0300 Numpy","permalink":"/blog/cach-bieu-dien-histogram"}},"content":"Th\xf4ng th\u01b0\u01a1\u0300ng, khi visualize m\u0103\u0323c \u0111i\u0323nh histogram cu\u0309a seaborn se\u0303 kh\xf4ng th\xea\u0309 hi\xea\u0323n t\xe2\u0301t ca\u0309 ca\u0301c nha\u0303n cu\u0309a bins va\u0300 s\xf4\u0301 l\u01b0\u01a1\u0323ng m\xf4\u0303i bin\\nV\u01a1\u0301i ca\u0301ch la\u0300m nh\u01b0 tr\xean se\u0303 r\xe2\u0301t kho\u0301 theo do\u0303i ca\u0301c khoa\u0309ng gia\u0301 tri\u0323 cu\u0309a t\u01b0\u0300ng bin va\u0300 s\xf4\u0301 l\u01b0\u01a1\u0323ng cu\u0309a bin \u0111o\u0301. May m\u0103\u0301n thay seaborn histogram t\u01b0\u01a1ng t\u01b0\u0323 numpy n\xean ta co\u0301 th\xea\u0309 du\u0300ng ha\u0300m np.histogram \u0111\xea\u0309 gia\u0309i quy\xea\u0301t v\xe2\u0301n \u0111\xea\u0300 na\u0300y\\n\x3c!-- truncate --\x3e\\n\\n## D\xe2\u0301u hi\xea\u0323u cu\u0309a m\xf4\u0323t bi\xea\u0309u \u0111\xf4\u0300 tr\u01b0\u0323c quan ke\u0301m \\n\\n- D\u01b0\u0303 li\xea\u0323u li\xean quan bi\u0323 \xe2\u0309n: Nh\u01b0\u0303ng th\xf4ng tin c\xe2\u0300n thi\xea\u0301t bi\u0323 che khu\xe2\u0301t ho\u0103\u0323c kh\xf4ng \u0111\u01b0\u01a1\u0323c \u0111a\u0301nh d\xe2\u0301u\\n- Bi\xea\u0309u \u0111\xf4\u0300 qua\u0301 ta\u0309i: Bao g\xf4\u0300m qua\u0301 nhi\xea\u0300u th\xf4ng tin khi\xea\u0301n bi\xea\u0309u \u0111\xf4\u0300 kho\u0301 \u0111o\u0323c\\n- Sai l\xea\u0323ch d\u01b0\u0303 li\xea\u0323u: S\u01b0\u0309 du\u0323ng ti\u0309 l\xea\u0323  ho\u0103\u0323c \u0111i\u0323nh da\u0323ng d\u01b0\u0303 li\xea\u0323u sai\\n- M\xf4 ta\u0309 d\u01b0\u0303 li\xea\u0323u sai: M\xf4 ta\u0309 d\u01b0\u0303 li\xea\u0323u kh\xf4ng \u0111u\u0301ng v\u01a1\u0301i hi\u0300nh ve\u0303\\n- Hi\u0300nh a\u0309nh kho\u0301 hi\xea\u0309u: Thi\xea\u0301t k\xea\u0301 hi\u0300nh a\u0309nh g\xe2y kho\u0301 hi\xea\u0309u la\u0300m cho ng\u01b0\u01a1\u0300i \u0111o\u0323c kh\xf4ng n\u0103\u0301m \u0111\u01b0\u01a1\u0323c th\xf4ng tin\\n\\n## \u0110\xf4\u0323 t\u01b0\u01a1ng pha\u0309n ma\u0300u g\xe2y hi\xea\u0309u l\xe2\u0300m\\n\\n**\u0110\u01b0a qua\u0301 nhi\xea\u0300u th\xf4ng tin kh\xf4ng li\xean quan**\\n\\nM\xf4\u0323t sai l\xe2\u0300m ph\xf4\u0309 bi\xea\u0301n la\u0300 \u0111\u01b0a qua\u0301 nhi\xea\u0300u ma\u0300u va\u0300o visualize. Vi\u0301 du\u0323 ve\u0303 bi\xea\u0309u \u0111\xf4\u0300 scatter plot v\xea\u0300 d\xe2n s\xf4\u0301 va\u0300 t\xf4\u0301c \u0111\xf4\u0323 t\u0103ng tr\u01b0\u01a1\u0309ng d\xe2n s\xf4\u0301 cu\u0309a Vi\xea\u0323t Nam, v\u01a1\u0301i 63 ti\u0309nh tha\u0300nh ta co\u0301 63 ma\u0300u cho m\xf4\u0303i ti\u0309nh, \u0111i\xea\u0300u na\u0300y g\xe2y ra v\xe2\u0301n \u0111\xea\u0300 kho\u0301 kh\u0103n khi nh\xe2\u0323n bi\xea\u0301t ma\u0300u na\u0300o la\u0300 cu\u0309a ti\u0309nh tha\u0300nh na\u0300o. Theo nguy\xean t\u0103\u0301c chung, thang ma\u0300u ch\xe2\u0301t l\u01b0\u01a1\u0323ng hoa\u0323t \u0111\xf4\u0323ng t\xf4\u0301t nh\xe2\u0301t khi co\u0301 ba \u0111\xea\u0301n n\u0103m loa\u0323i ma\u0300u kha\u0301c nhau. Do \u0111o\u0301, thay vi\u0300 \u0111\xea\u0309 63 ma\u0300u cho 63 ti\u0309nh tha\u0300nh, chu\u0301ng ta n\xean ph\xe2n chia ma\u0300u theo 7 khu v\u01b0\u0323c kinh t\xea\u0301 (ho\u0103\u0323c 3 mi\xea\u0300n) va\u0300 \u0111\xea\u0309 xa\u0301c \u0111i\u0323nh t\u01b0\u0300ng ti\u0309nh tha\u0300nh, chu\u0301ng ta th\xeam ca\u0301c nha\u0303n ti\u0309nh tha\u0300nh va\u0300o bi\xea\u0309u \u0111\xf4\u0300. Di\u0303 nhi\xean chu\u0301ng ta kh\xf4ng c\xe2\u0300n pha\u0309i th\xeam t\xe2\u0301t ca\u0309 ca\u0301c nha\u0303n cu\u0309a t\xe2\u0301t ca\u0309 ti\u0309nh tha\u0300nh va\u0300o bi\xea\u0309u \u0111\xf4\u0300 ma\u0300 chi\u0309 c\xe2\u0300n th\xeam m\xf4\u0323t va\u0300i nha\u0303n ti\xeau bi\xea\u0309u \u01b0\u0301ng v\u01a1\u0301i t\u01b0\u0300ng khu v\u01b0\u0323c. Ngoa\u0300i ra, chu\u0301ng ta c\xe2\u0300n n\xean ke\u0300m theo d\u01b0\u0303 li\xea\u0323u da\u0323ng ba\u0309ng v\u01a1\u0301i ca\u0301c th\xf4ng tin \u0111\xe2\u0300y \u0111u\u0309 \u0111\xea\u0309 ng\u01b0\u01a1\u0300i \u0111o\u0323c co\u0301 th\xea\u0309 truy c\xe2\u0323p toa\u0300n b\xf4\u0323 d\u01b0\u0303 li\xea\u0323u.\\n\\n\\n\u0110\xf4\u0301i v\u01a1\u0301i da\u0323ng barchart vi\xea\u0323c s\u01b0\u0309 du\u0323ng qua\u0301 nhi\xea\u0300u ma\u0300u s\u0103\u0301c(ma\u0300u c\xe2\u0300u v\xf4\u0300ng) kh\xf4ng th\xea\u0309 hi\xea\u0323n \u0111\u01b0\u01a1\u0323c mu\u0323c \u0111i\u0301ch cu\u0309a ma\u0300u s\u0103\u0301c trong bi\xea\u0309u \u0111\xf4\u0300 na\u0300y\\n\\n![image](https://clauswilke.com/dataviz/pitfalls_of_color_use_files/figure-html/popgrowth-US-rainbow-1.png)\\n\\n\\n**S\u01b0\u0309 du\u0323ng thang ma\u0300u kh\xf4ng \u0111\u01a1n \u0111i\xea\u0323u(non-monotonic) \u0111\xea\u0309 ma\u0303 ho\u0301a gia\u0301 tri\u0323 d\u01b0\u0303 li\xea\u0323u**\\n\\n**Kh\xf4ng thi\xea\u0301t k\xea\u0301 ma\u0300u cho ng\u01b0\u01a1\u0300i gia\u0309m thi\u0323 l\u01b0\u0323c ma\u0300u s\u0103\u0301c**\\n\\nhttps://clauswilke.com/dataviz/color-pitfalls.html\\n\\n\\n**Ta\u0301c \u0111\xf4\u0323ng cu\u0309a l\xf4\u0303i**\\n\\n- Ng\u01b0\u01a1\u0300i du\u0300ng hi\xea\u0309u nh\xe2\u0300m gia\u0301 tri\u0323 na\u0300o quan tro\u0323ng h\u01a1n\\n- M\xe2\u0301t th\u01a1\u0300i gian \u0111\xea\u0309 hi\xea\u0309u th\xf4ng tin\\n\\n**Ca\u0301ch gia\u0309i quy\xea\u0301t**\\n\\n- S\u01b0\u0309 du\u0323ng da\u0309i ma\u0300u ng\u0103\u0301n \u0111\xea\u0309 hi\xea\u0309n thi\u0323 gia\u0301 tri\u0323 cao h\u01a1n gia\u0301 tri\u0323 kha\u0301c (vi\u0301 du\u0323 \u0111o\u0309 -> va\u0300ng)\\n- Ca\u0301ch \u0111\u01a1n gia\u0309n nh\xe2\u0301t la\u0300 chuy\xea\u0309n da\u0300i ma\u0300u \u0111o\u0301 v\xea\u0300 m\u01b0\u0301c xa\u0301m xem ma\u0300u ba\u0323n cho\u0323n co\u0301 th\xea\u0309 hi\xea\u0323n s\u01b0\u0323 kha\u0301c bi\xea\u0323t kh\xf4ng\\n- S\u01b0\u0309 du\u0323ng t\xf4ng ma\u0300u no\u0301ng/la\u0323nh \u0111\xea\u0309 th\xea\u0309 hi\xea\u0323n gia\u0301 tri\u0323 \u0111\xf4\u0301i nghi\u0323ch (ti\xeau c\u01b0\u0323c/ti\u0301ch c\u01b0\u0323c)"},{"id":"cach-bieu-dien-histogram","metadata":{"permalink":"/blog/cach-bieu-dien-histogram","source":"@site/blog/2024/02/18/2024-02-18-visual-histogram.md","title":"Ca\u0301ch bi\xea\u0309u di\xea\u0303n s\xf4\u0301 l\u01b0\u01a1\u0323ng va\u0300 khoa\u0309ng d\u01b0\u0303 li\xea\u0323u cho Histogram du\u0300ng Seaborn va\u0300 Numpy","description":"This is my first post on Docusaurus.","date":"2024-02-18T00:00:00.000Z","formattedDate":"18 th\xe1ng 2, 2024","tags":[{"label":"data visualization","permalink":"/blog/tags/data-visualization"},{"label":"histogram","permalink":"/blog/tags/histogram"},{"label":"seaborn","permalink":"/blog/tags/seaborn"},{"label":"plot","permalink":"/blog/tags/plot"}],"readingTime":2.025,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"Ca\u0301ch bi\xea\u0309u di\xea\u0303n s\xf4\u0301 l\u01b0\u01a1\u0323ng va\u0300 khoa\u0309ng d\u01b0\u0303 li\xea\u0323u cho Histogram du\u0300ng Seaborn va\u0300 Numpy","description":"This is my first post on Docusaurus.","slug":"cach-bieu-dien-histogram","authors":"lhduc","tags":["data visualization","histogram","seaborn","plot"],"image":"https://i.imgur.com/mErPwqL.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"10 l\xf4\u0303i sai trong data visualization va\u0300 ca\u0301ch pho\u0300ng tra\u0301nh","permalink":"/blog/10-loi-sai-visualization"},"nextItem":{"title":"Data Envelopment Analysis","permalink":"/blog/data-envelopment-analysis-phan-tich-hieu-suat"}},"content":"Th\xf4ng th\u01b0\u01a1\u0300ng, khi visualize m\u0103\u0323c \u0111i\u0323nh histogram cu\u0309a seaborn se\u0303 kh\xf4ng th\xea\u0309 hi\xea\u0323n t\xe2\u0301t ca\u0309 ca\u0301c nha\u0303n cu\u0309a bins va\u0300 s\xf4\u0301 l\u01b0\u01a1\u0323ng m\xf4\u0303i bin\\nV\u01a1\u0301i ca\u0301ch la\u0300m nh\u01b0 tr\xean se\u0303 r\xe2\u0301t kho\u0301 theo do\u0303i ca\u0301c khoa\u0309ng gia\u0301 tri\u0323 cu\u0309a t\u01b0\u0300ng bin va\u0300 s\xf4\u0301 l\u01b0\u01a1\u0323ng cu\u0309a bin \u0111o\u0301. May m\u0103\u0301n thay seaborn histogram t\u01b0\u01a1ng t\u01b0\u0323 numpy n\xean ta co\u0301 th\xea\u0309 du\u0300ng ha\u0300m np.histogram \u0111\xea\u0309 gia\u0309i quy\xea\u0301t v\xe2\u0301n \u0111\xea\u0300 na\u0300y\\n\x3c!-- truncate --\x3e\\n\\nD\u01b0\u1edbi \u0111\xe2y l\xe0 v\xed d\u1ee5 c\u01a1 b\u1ea3n khi visualize d\u1eef li\u1ec7u b\u1eb1ng histogram m\u1eb7c \u0111\u1ecbnh c\u1ee7a seaborn\\n\\n```python\\nimport numpy as np\\nimport seaborn as sns \\nnp.random.seed(42)\\nx = np.random.uniform(size=200)\\nsns.histplot(x, bins=10)\\n```\\n\\n![Example banner](1709112253837.jpg)\\n\\nK\u1ebft qu\u1ea3 kh\xf4ng cho ta th\u1ea5y \u0111\u01b0\u1ee3c bin \u0111\u1ea7u ti\xean n\u1eb1m trong kho\u1ea3ng gi\xe1 tr\u1ecb n\xe0o, v\xe0 s\u1ed1 l\u01b0\u1ee3ng ph\u1ea7n t\u1eed l\xe0 bao nhi\xeau, \u0111i\u1ec1u n\xe0y d\u1eabn \u0111\u1ebfn kh\xf3 kh\u0103n \u0111\u1ec3 hi\u1ec3u \u0111\u01b0\u1ee3c bi\u1ec3u \u0111\u1ed3 c\u0169ng nh\u01b0 \u0111\xe1nh gi\xe1 k\u1ebft qu\u1ea3. \u0110\u1ec3 gi\u1ea3i quy\u1ebft v\u1ea5n \u0111\u1ec1 tr\xean, ch\xfang ta t\xecm c\xe1ch \u0111i\u1ec1n v\xe0o bi\u1ec3u \u0111\u1ed3 b\u1eb1ng ph\u01b0\u01a1ng th\u1ee9c `plt.text`. Tr\u01b0\u1edbc h\u1ebft, ch\xfang ta c\u1ea7n t\xednh \u0111\u01b0\u1ee3c kho\u1ea3ng m\u1ed7i bin v\xe0 s\u1ed1 l\u01b0\u1ee3ng c\xe1c ph\u1ea7n t\u1eed trong bin, may m\u1eafn thay np.histogram c\xf3 th\u1ec3 gi\xfap ta t\xednh \u0111\u01b0\u1ee3c c\xe1c gi\xe1 tr\u1ecb n\xe0y\\n\\n```python\\ncounts, bin_labels = np.histogram(x, bins=10)\\nprint(len(counts), counts)\\nprint(len(bin_labels), bin_labels)\\n```\\n\\n```\\n10 [22 24 20 24 11 19 20 18 18 24]\\n11 [0.00552212 0.1036586  0.20179508 0.29993156 0.39806804 0.49620453\\n 0.59434101 0.69247749 0.79061397 0.88875045 0.98688694]\\n```\\n\\nCa\u0301c ba\u0323n co\u0301 th\xea\u0309 th\xe2\u0301y v\u01a1\u0301i tham s\xf4\u0301 bins \u0111\u01b0a va\u0300o chi\u0309 co\u0301 10 trong khi k\xea\u0301t qua\u0309 nha\u0303n bin_labels la\u0323i co\u0301 11 gia\u0301 tri\u0323, trong \u0111o\u0301 gia\u0301 tri\u0323 \u0111\xe2\u0300u la\u0300 gia\u0301 tri\u0323 nho\u0309 nh\xe2\u0301t cu\u0309a x va\u0300 gia\u0301 tri\u0323 cu\xf4\u0301i la\u0300 gia\u0301 tri\u0323 cao nh\xe2\u0301t cu\u0309a x. Do \u0111o\u0301 khoa\u0309ng \u0111\xe2\u0300u ti\xean cu\u0309a bin \u0111\xe2\u0300u ti\xean co\u0301 gia\u0301 tri\u0323 n\u0103\u0300m t\u01b0\u0300 [0.00552212, 0.1036586)\\n\u0110\xea\u0309 ki\xea\u0309m tra xem co\u0301 \u0111u\u0301ng th\xea\u0309 kh\xf4ng, vi\u0301 du\u0323 ki\xea\u0309m tra bin \u0111\xe2\u0300u ti\xean co\u0301 pha\u0309i 22 ph\xe2\u0300n t\u01b0\u0309 kh\xf4ng?\\n\\n```python\\nlen(x[(x>=bin_labels[0]) & (x<bin_labels[1])])\\n```\\n\\n```\\n22\\n```\\n\\nSau \u0111o\u0301, ta du\u0300ng matplotlib \u0111\xea\u0309 plot text\\n\\n```python\\nimport matplotlib.pyplot as plt \\n\\nax = sns.histplot(x, bins=10)\\nbin_heights = [p.get_height() if p.get_height() > 0 else 0.1 for p in ax.patches]\\n# Hi\u1ec3n th\u1ecb gi\xe1 tr\u1ecb count t\u1eebng bin\\nfor i in range(len(bin_heights)):\\n    plt.text(ax.patches[i].get_x() + ax.patches[i].get_width() / 2,\\n            bin_heights[i],\\n            str(int(bin_heights[i])),\\n            fontsize=14,\\n            ha=\'center\',\\n            va=\'bottom\')\\nmids = [rect.get_x() + rect.get_width() / 2 for rect in ax.patches]\\nlabels = [(round(i,2),round(j,2)) for i,j in zip(bin_labels[:-1], bin_labels[1:])]\\nax.set_xticks(mids, labels=labels, fontsize=14, rotation=90)\\nax.set_ylim(0,28)\\n```\\n\\n![Example banner](1709112655963.png)"},{"id":"data-envelopment-analysis-phan-tich-hieu-suat","metadata":{"permalink":"/blog/data-envelopment-analysis-phan-tich-hieu-suat","source":"@site/blog/2024/01/15/2024-01-15-Data-Envelopment-Analysis.md","title":"Data Envelopment Analysis","description":"Ph\xe2n ti\u0301ch hi\xea\u0323u su\xe2\u0301t.","date":"2024-01-15T00:00:00.000Z","formattedDate":"15 th\xe1ng 1, 2024","tags":[{"label":"data visualization","permalink":"/blog/tags/data-visualization"},{"label":"histogram","permalink":"/blog/tags/histogram"},{"label":"seaborn","permalink":"/blog/tags/seaborn"},{"label":"plot","permalink":"/blog/tags/plot"}],"readingTime":1.29,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"Data Envelopment Analysis","description":"Ph\xe2n ti\u0301ch hi\xea\u0323u su\xe2\u0301t.","slug":"data-envelopment-analysis-phan-tich-hieu-suat","authors":"lhduc","tags":["data visualization","histogram","seaborn","plot"],"image":"https://i.imgur.com/mErPwqL.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Ca\u0301ch bi\xea\u0309u di\xea\u0303n s\xf4\u0301 l\u01b0\u01a1\u0323ng va\u0300 khoa\u0309ng d\u01b0\u0303 li\xea\u0323u cho Histogram du\u0300ng Seaborn va\u0300 Numpy","permalink":"/blog/cach-bieu-dien-histogram"},"nextItem":{"title":"Covariance va\u0300 Correlation","permalink":"/blog/covariance-correlation"}},"content":"**\u0110a\u0301nh gia\u0301 Hi\xea\u0323u su\xe2\u0301t la\u0300 gi\u0300\u200b?**\\n\\nKhi chu\u0301ng ta co\u0301 \u0111\xe2\u0300u va\u0300o, va\u0300 nh\xe2\u0323n \u0111\u01b0\u01a1\u0323c k\xea\u0301t qua\u0309, chu\u0301ng ta hay \u0111a\u0301nh gia\u0301 hi\xea\u0323u su\xe2\u0301t cu\u0309a k\xea\u0301t qua\u0309 xem v\u01a1\u0301i \u0111\xe2\u0300u va\u0300o nh\u01b0 th\xea\u0301 thi\u0300 k\xea\u0301t qua\u0309 li\xea\u0323u co\u0301 t\xf4\u0301t kh\xf4ng.\u200b M\xf4\u0323t s\xf4\u0301 vi\u0301 du\u0323 c\u01a1 ba\u0309n: Gia\u0301 tha\u0300nh/sa\u0309n ph\xe2\u0309m, L\u01a1\u0323i nhu\xe2\u0323n/sa\u0309n ph\xe2\u0309m.\u200b\\n\x3c!-- truncate --\x3e\\n\\n$$\\n\\\\frac{Output}{Input}\\n$$\\n\\nC\xf4ng th\u01b0\u0301c tr\xean \u0111\u01b0\u01a1\u0323c go\u0323i la\u0300 th\u01b0\u01a1\u0301c \u0111o hi\xea\u0323u qua\u0309.\u200b\\nChu\u0301ng ta co\u0301 th\xea\u0309 m\u01a1\u0309 r\xf4\u0323ng c\xf4ng th\u01b0\u0301c tr\xean v\u01a1\u0301i Nhi\xea\u0300u \u0111\xe2\u0300u va\u0300o (Inputs) va\u0300 nhi\xea\u0300u \u0111\xe2\u0300u ra (Outputs)\u200b\\n\\n![](efficient_frontier.png)\\n\u0110\xf4\u0323 d\xf4\u0301c cu\u0309a \u0111\u01b0\u01a1\u0300ng n\xf4\u0301i v\u01a1\u0301i m\xf4\u0303i \u0111i\xea\u0309m va\u0300 g\xf4\u0301c to\u0323a \u0111\xf4\u0323 t\u01b0\u01a1ng \u01b0\u0301ng v\u01a1\u0301i Sales/ Employee ( hi\xea\u0323u qua\u0309).\u200b\\n\\n\u0110\u01b0\u01a1\u0300ng co\u0301 \u0111\xf4\u0323 d\xf4\u0301c cao nh\xe2\u0301t (n\xf4\u0301i v\u01a1\u0301i \u0111i\xea\u0309m B) \u0111\u01b0\u01a1\u0323c go\u0323i la\u0300 Efficient  Frontier (\u0110\u01b0\u01a1\u0300ng bi\xean hi\xea\u0323u qua\u0309).\u200b\\n\\nCa\u0301c \u0111i\xea\u0309m se\u0303 n\u0103\u0300m cu\u0300ng 1 phi\u0301a so v\u01a1\u0301i \u0111\u01b0\u01a1\u0300ng th\u0103\u0309ng, ho\u0103\u0323c \u01a1\u0309 tr\xean, ho\u0103\u0323c \u01a1\u0309 d\u01b0\u01a1\u0301i.\u200b\\n\\nVi\u0300 \u0111\u01b0\u01a1\u0300ng bi\xean na\u0300y bao bo\u0323c ca\u0301c \u0111i\xea\u0309m d\u01b0\u0303 li\xea\u0323u, n\xean ph\xe2n ti\u0301ch na\u0300y \u0111\u01b0\u01a1\u0323c go\u0323i la\u0300 Data Envelopment Analysis.\u200b\\n\\n\\n\\nChu\u0301ng ta co\u0301 th\xea\u0309  ve\u0303 m\xf4\u0323t \u0111\u01b0\u01a1\u0300ng th\xf4\u0301ng k\xea h\xf4\u0300i quy $y=0.622x$ \u0111\xea\u0309 \u01b0\u01a1\u0301c l\u01b0\u01a1\u0323ng m\xf4\u0301i quan h\xea\u0323 tuy\xea\u0301n ti\u0301nh gi\u01b0\u0303a input va\u0300 output.\u200b\\n\\n\u0110\u01b0\u01a1\u0300ng h\xf4\u0300i quy na\u0300y \u0111i qua chi\u0301nh gi\u01b0\u0303a cu\u0309a t\xe2\u0323p d\u01b0\u0303 li\xea\u0323u, do \u0111o\u0301 chu\u0301ng ta co\u0301 th\xea\u0309 xem ca\u0301c \u0111i\xea\u0309m \u01a1\u0309 phi\u0301a tr\xean \u0111\u01b0\u01a1\u0300ng la\u0300 hi\xea\u0323u qua\u0309 t\xf4\u0301t va\u0300 \u0111i\xea\u0309m d\u01b0\u01a1\u0301i la\u0300 ch\u01b0a t\xf4\u0301t, khoa\u0309ng ca\u0301ch gi\u01b0\u0303a \u0111i\xea\u0309m t\u01a1\u0301i \u0111\u01b0\u01a1\u0300ng h\xf4\u0300i quy chi\u0301nh ta m\u01b0\u0301c \u0111\xf4\u0323 hi\xea\u0323u qua\u0309/kh\xf4ng hi\xea\u0323u qua\u0309\u200b\\n\\nKhoa\u0309ng ca\u0301ch t\u01b0\u0300 ca\u0301c \u0111i\xea\u0309m \u0111\xea\u0301n \u0111\u01b0\u01a1\u0300ng Efficient Frontier n\xeau l\xean \u0111\xf4\u0323 l\xea\u0323ch so v\u01a1\u0301i \u0111i\xea\u0309m t\xf4\u0301t nh\xe2\u0301t\u200b\\n\\n![](efficiente_frontier_regression_line.png)"},{"id":"covariance-correlation","metadata":{"permalink":"/blog/covariance-correlation","source":"@site/blog/2020/06/15/2020-06-15-covariance-correlation.md","title":"Covariance va\u0300 Correlation","description":"Covariance va\u0300 Correlation.","date":"2020-06-15T00:00:00.000Z","formattedDate":"15 th\xe1ng 6, 2020","tags":[{"label":"math","permalink":"/blog/tags/math"},{"label":"correlation","permalink":"/blog/tags/correlation"},{"label":"covariance","permalink":"/blog/tags/covariance"}],"readingTime":3.175,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"Covariance va\u0300 Correlation","description":"Covariance va\u0300 Correlation.","slug":"covariance-correlation","authors":"lhduc","tags":["math","correlation","covariance"],"image":"https://miro.medium.com/v2/resize:fit:720/format:webp/0*ww9NZU5NWGL4miVT","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Data Envelopment Analysis","permalink":"/blog/data-envelopment-analysis-phan-tich-hieu-suat"}},"content":"![](https://miro.medium.com/v2/resize:fit:720/format:webp/0*ww9NZU5NWGL4miVT)\\n\\nCovariance (Hi\u1ec7p ph\u01b0\u01a1ng sai) v\xe0 Correlation (H\u1ec7 s\u1ed1 t\u01b0\u01a1ng quan) l\xe0 hai kh\xe1i ni\u1ec7m trong l\u0129nh v\u1ef1c x\xe1c su\u1ea5t th\u1ed1ng k\xea. C\u1ea3 hai kh\xe1i ni\u1ec7m n\xe0y \u0111\u1ec1u n\xf3i v\u1ec1 m\u1ed1i quan h\u1ec7 gi\u1eefa hai bi\u1ebfn v\u1edbi nhau, hay n\xf3i c\xe1ch kh\xe1c hai ch\u1ec9 s\u1ed1 n\xe0y d\xf9ng \u0111\u1ec3 th\u1ec3 hi\u1ec7n s\u1ef1 ph\u1ee5 thu\u1ed9c gi\u1eefa hai bi\u1ebfn.\\n\x3c!-- truncate --\x3e\\n\\n\\n## Covariance l\xe0 g\xec?\\nCovariance th\u1ec3 hi\u1ec7n m\u1ed1i quan h\u1ec7 gi\u1eefa hai bi\u1ebfn v\u1edbi nhau, c\xf3 th\u1ec3 l\xe0 \u0111\u1ed3ng bi\u1ebfn (positive covariance) ho\u1eb7c ngh\u1ecbch bi\u1ebfn (negative covariance).\\n\\n\u0110\u1ecbnh ngh\u0129a : Cho 2 bi\u1ebfn ng\u1eabu nhi\xean X, Y v\u1edbi k\xec v\u1ecdng $\\\\mu_X$ v\xe0 $\\\\mu_Y$  covariance c\u1ee7a X, Y \u0111\u01b0\u1ee3c t\xednh b\u1eb1ng c\xf4ng th\u1ee9c :\\n\\n$$\\nCov(X, Y)=E[(X\u2212\\\\mu_X)*(Y\u2212\\\\mu_Y)]\\n$$\\nC\xe1c t\xednh ch\u1ea5t c\u1ee7a Covariance :\\n\\n1. $Cov(aX + b, cY + d)=acCov(X, Y)$ v\u1edbi $a, b, c, d$ cho tr\u01b0\u1edbc\\n2. $Cov(X1 + X2 ,Y)=Cov(X1, Y) + Cov(X2, Y)$\\n3. $Cov(X, X)=Var(X)$\\n4. $Cov(X, Y)=E(XY)\u2212\\\\mu_X * \\\\mu_Y$\\n5. $Var(X, Y)=Var(X) + Var(Y) + 2 * Cov(X, Y)$\\n6. $X, Y$ \u0111\u1ed9c l\u1eadp th\xec $Cov(X, Y)=0$ .\\n\\nL\u01b0u \xfd :\\n\\nT\u1eeb $(3)$ v\xe0 $(4)$ ta c\xf3 $Var(X) = E(X^2) \u2212 (\\\\mu_X)^2$. N\u1ebfu X, Y \u0111\u1ed9c l\u1eadp t\u1eeb 5 c\xf3 th\u1ec3 suy ra \u0111\u01b0\u1ee3c $Var(X, Y)=Var(X) + Var(Y)$.\\n\\nV\u1edbi Ti\u0301nh ch\xe2\u0301t $(6)$, \u0111i\u1ec1u ng\u01b0\u1ee3c l\u1ea1i kh\xf4ng \u0111\xfang, ngh\u0129a l\xe0 $Cov(X, Y)=0$ kh\xf4ng c\xf3 ngh\u0129a l\xe0 X, Y \u0111\u1ed9c l\u1eadp v\u1edbi nhau. \\nV\xed d\u1ee5 $X = [-2 , -1 , 1 , 2]$ v\xe0 $Y = X^2 = [4 , 1, 1 , 4]$ khi \u0111\xf3 $Cov(X, Y)=0$ m\u0103\u0323c du\u0300 X va\u0300 Y co\u0301 m\xf4\u0301i t\u01b0\u01a1ng quan v\u01a1\u0301i nhau\\n\\n## Correlation l\xe0 g\xec?\\n\\n\u0110\u1ec3 th\u1ec3 hi\u1ec7n m\u1ed1i quan h\u1ec7 gi\u1eefa 2 bi\u1ebfn l\xe0 \u201cm\u1ea1nh\u201d hay \u201cy\u1ebfu\u201d, ch\xfang ta s\u1eed d\u1ee5ng correlation thay cho covariance.\\n\\n\u0110\u1ecbnh ngh\u0129a : Correlation coefficient c\u1ee7a hai bi\u1ebfn X v\xe0 Y \u0111\u01b0\u1ee3c t\xednh theo c\xf4ng th\u1ee9c\\n\\n$$\\nCor(X,Y) = \u03c1= Cov(X, Y) / (\\\\sigma_X * \\\\sigma_Y)\\n$$\\n\\n\\n**C\xe1c t\xednh ch\u1ea5t c\u1ee7a Correlation**\\n\\n1. Correlation l\xe0 Covariance \u0111\u01b0\u1ee3c chu\u1ea9n h\xf3a c\u1ee7a hai bi\u1ebfn X, Y\\n\\n2. Correlation th\u1ec3 hi\u1ec7n m\u1ed9t t\u1ec9 l\u1ec7, do \u0111\xf3 n\xf3 kh\xf4ng c\xf3 \u0111\u01a1n v\u1ecb \u0111o\\n\\n3. $\u22121 \\\\le \\\\rho \\\\le 1$ ($\\\\rho = \u22121$ khi va\u0300 chi\u0309 khi $Y = aX + b$ va\u0300  $a \\\\lt 0$ va\u0300 $\\\\rho = 1$ khi v\xe0 ch\u1ec9 khi $Y = aX + b$ va\u0300 $a \\\\gt 0$) \\n\\nCh\u1ee9ng minh t\xednh ch\u1ea5t 3\\n\\n\\n$$\\n0 \\\\le Var(\\\\frac{X}{\\\\sigma_X}\u2212\\\\frac{Y}{\\\\sigma_{Y}}) = Var(\\\\frac{X}{\\\\sigma_X}) + Var(\\\\frac{Y}{\\\\sigma_Y}) \u2212 2Cov(\\\\frac{X}{\\\\sigma_X},\\\\frac{Y}{\\\\sigma_Y}) = 2 \u2212 2\\\\rho \\\\Rightarrow  \\\\rho \\\\le 1 \\n$$\\n\\nT\u01b0\u01a1ng t\u1ef1 $0 \\\\le Var(\\\\frac{X}{\\\\sigma_X}+\\\\frac{Y}{\\\\sigma_{Y}}) \\\\Rightarrow  \\\\rho \\\\ge \u22121$\\n\\n**Bi\u1ec3u di\u1ec5n m\u1ed1i quan h\u1ec7 X, v\xe0 Y v\u1edbi gi\xe1 tr\u1ecb $\\\\rho$ (correlation)**\\n![](https://miro.medium.com/v2/resize:fit:640/format:webp/0*HDrVqgtu3QUN6ltX.png)\\n\\n## So s\xe1nh gi\u1eefa covariance v\xe0 correlation\\n\\n\\n1. C\u1ea3 covariance v\xe0 correlation \u0111\u1ec1u th\u1ec3 hi\u1ec7n m\u1ed1i quan h\u1ec7 gi\u1eefa hai bi\u1ebfn.\\n2. Covariance c\xf3 range t\u1eeb $-\\\\infty$ \u0111\xea\u0301n $+\\\\infty$ . Correlation n\u0103\u0300m trong khoa\u0309ng t\u01b0\u0300 - 1 \u0111\xea\u0301n 1.\\n3. Covariance th\xea\u0309 hi\xea\u0323n m\xf4\u0301i quan h\xea\u0323 gi\u01b0\u0303a hai bi\xea\u0301n, correlation th\xea\u0309 hi\xea\u0323n \u0111\u01b0\u01a1\u0323c m\xf4\u0301i quan h\xea\u0323 gi\u01b0\u0303a hai ho\u0103\u0323c nhi\xea\u0300u bi\xea\u0301n.\\n\\n**Vi\u0301 du\u0323**\\n\\nT\xe2\u0323p d\u01b0\u0303 li\xea\u0323u view cu\u0309a 2 k\xeanh truy\xea\u0300n hi\u0300nh ta\u0323i 1 th\u01a1\u0300i \u0111i\xea\u0309m (20h - 21h th\u01b0\u0301 n\u0103m m\xf4\u0303i tu\xe2\u0300n) trong 1 tha\u0301ng la\u0300\\n\\n$X = [50772, 73756, 74251, 77601]$\\n\\n$Y = [102492, 100406, 97762, 98191]$\\n\\nTa ti\u1ebfn h\xe0nh t\xednh c\xe1c th\xf4ng s\u1ed1 c\u01a1 b\u1ea3n\\n\\n$\\\\mu_X = \\\\frac{50772 + 73756 + 74251 + 77601}{4} = 69095.00$\\n\\n$\\\\mu_Y = \\\\frac{102492 + 100406 + 97762 + 98191}{4} = 99712.75$\\n\\n$\\\\sigma_X^2 = \\\\frac{(50772 - \\\\mu_X)^2 +(73756 - \\\\mu_X)^2 + ... }{4} = 114098405.5 \\\\Rightarrow  \\\\sigma_X = 10681.69$\\n\\n$\\\\sigma_Y^2 = \\\\frac{(102492 - \\\\mu_Y)^2 +(100406 - \\\\mu_Y)^2 + ... }{4} = 114098405.5 \\\\Rightarrow  \\\\sigma_Y = 1892.48$\\n\\nT\u1eeb \u0111\xf3 ta t\xednh covariance v\xe0 correlation\\n\\n$Cov(X,Y) = \\\\frac{(50772 - 69095.00) * (102492- 99712.75) + (73756- 69095.00) * (100406- 99712.75) + ... }{4} = -17673758.0$\\n\\n$Corr(X,Y) = \\\\frac{Cov(X,Y)}{\\\\sigma_X * \\\\sigma_Y} = \\\\frac{-17673758.0} {10681.69 * 1892.48} = -0.87$"}]}')}}]);